Javascript.isEnabled:
var allocationQuestionnaireFeePaid = Services.getValue(AllocationQuestionnaireFeePaid.dataBinding);
if (allocationQuestionnaireFeePaid == "Y")
{
	Services.setValue(PartyWhoHasNotPaidFee.dataBinding, "");
	return false;
}
else
{
	return true;
}

Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/PartyList/Party[./Value = " + PartyWhoHasNotPaidFee.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/PartyList/Party[./Description = " + PartyWhoHasNotPaidFee.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.transformToDisplay:
var description = Services.getValue( REF_DATA_XPATH + "/PartyList/Party[./Value = " + PartyWhoHasNotPaidFee.dataBinding + "]/Description" );
if (description != null)
{
	return description;
}
else
{
	return value;
}

